class Solution(object):
    def advantageCount(self, nums1, nums2):
        sorted1 = sorted(enumerate(nums1), key=lambda x: x[1])
        sorted2 = sorted(enumerate(nums2), key=lambda x: x[1])
        result = [0] * len(nums1)
        j = 0
        for idx2, val2 in sorted2:
            if j < len(sorted1) and sorted1[j][1] > val2:
                result[idx2] = sorted1[j][1]
                j += 1
            else:
                result[idx2] = sorted1[j if j < len(sorted1) else len(sorted1) - 1][1]
                if j < len(sorted1):
                    j += 1
        return result
